1	const PROCESSING_FEE = 5;
2	const FIRST_CONTRACT_INSURANCE_RATE = 0.1;
3	const COMPONENT_BASE_PREMIUM = 25;
4	const BUILDING_BLOCK_SIZE = 3;
5	const BUILDING_BLOCK_BASE_PREMIUM = 60;
6	
7	type Item = { type: string };
8	type QuoteStep = { op: "quote"; items: Item[] };
9	type Step = QuoteStep;
10	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
11	
12	const MAIN_ITEM_BASE_PREMIUM: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	};
18	
19	const COMPONENT_TYPES = new Set(["rune"]);
20	
21	const isComponent = (item: Item) => COMPONENT_TYPES.has(item.type);
22	
23	const componentGroupBase = (count: number): number => {
24	  if (count === BUILDING_BLOCK_SIZE) return BUILDING_BLOCK_BASE_PREMIUM;
25	  return count * COMPONENT_BASE_PREMIUM;
26	};
27	
28	const componentBaseSum = (components: Item[]): number => {
29	  const countsByType = new Map<string, number>();
30	  for (const item of components) {
31	    countsByType.set(item.type, (countsByType.get(item.type) ?? 0) + 1);
32	  }
33	  let total = 0;
34	  for (const count of countsByType.values()) {
35	    total += componentGroupBase(count);
36	  }
37	  return total;
38	};
39	
40	const itemBaseSum = (items: Item[]): number => {
41	  const mainItems = items.filter((i) => !isComponent(i));
42	  const components = items.filter(isComponent);
43	  const mainSum = mainItems.reduce((sum, item) => sum + MAIN_ITEM_BASE_PREMIUM[item.type], 0);
44	  return mainSum + componentBaseSum(components);
45	};
46	
47	const quotePremium = (items: Item[]): number => {
48	  const base = itemBaseSum(items);
49	  const firstContractInsurance = base * FIRST_CONTRACT_INSURANCE_RATE;
50	  return Math.ceil(base + firstContractInsurance + PROCESSING_FEE);
51	};
52	
53	export const runScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => {
54	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
55	  return { results };
56	};
